// src/pages/TimbangMuat.jsx
import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

const TimbangMuat = () => {
  const [rfidValue, setRfidValue] = useState(null);
  const [truck, setTruck] = useState(null);
  const [form, setForm] = useState({
    itemType: '',
    quantity: '',
    bruto: '',
    tara: '',
    netto: ''
  });

  const apiUrl = 'http://localhost:5000';

  // Polling RFID setiap 5 detik
  useEffect(() => {
    const interval = setInterval(fetchRFID, 5000);
    return () => clearInterval(interval);
  }, []);

  const fetchRFID = async () => {
    try {
      const res = await fetch(`${apiUrl}/api/rfid/latest`);
      const data = await res.json();

      if (data && data.truck) {
        setRfidValue(data.truck.truckId);
        fetchTruckData(data.truck.truckId);
      } else {
        setRfidValue(null);
        setTruck(null);
      }
    } catch (err) {
      console.error("Gagal ambil data RFID:", err);
    }
  };

  const fetchTruckData = async (truckId) => {
    try {
      const res = await fetch(`${apiUrl}/api/trucks/${truckId}`);
      const data = await res.json();
      setTruck(data);
    } catch (err) {
      console.error("Gagal ambil data truk:", err);
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    let newForm = { ...form, [name]: value };

    if (name === 'bruto' || name === 'tara') {
      const bruto = parseFloat(newForm.bruto || 0);
      const tara = parseFloat(newForm.tara || 0);
      newForm.netto = bruto - tara;
    }

    setForm(newForm);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!truck) {
      alert("Silakan scan kartu terlebih dahulu!");
      return;
    }

    const payload = {
      truckId: truck.truckId,
      itemType: form.itemType,
      quantity: form.quantity,
      bruto: form.bruto,
      tara: form.tara,
      netto: form.netto
    };

    try {
      const res = await fetch(`${apiUrl}/api/loadings`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });
      const data = await res.json();
      if (res.ok) {
        alert("Data Timbang Muat berhasil disimpan");
        setForm({ itemType: '', quantity: '', bruto: '', tara: '', netto: '' });
      } else {
        alert(data.message || 'Gagal menyimpan data');
      }
    } catch (err) {
      alert("Koneksi ke server gagal");
      console.error(err);
    }
  };

  return (
    <div className="flex min-h-screen bg-gradient-to-br from-green-100 to-blue-200">
      {/* Sidebar */}
      <div className="bg-gray-800 text-white w-64 p-6 flex flex-col justify-between">
        <div>
          <div className="flex flex-col items-center mb-6">
            <img src="/images/admin.png" alt="Admin Icon" className="rounded-full mb-2 w-16 h-16 object-cover" />
            <h2 className="font-semibold text-lg">Admin</h2>
          </div>
          <div className="space-y-6">
            <Link to="/master-data" className="block bg-gray-700 rounded-lg p-3 text-center">Master Data</Link>
            <Link to="/tracking" className="block bg-gray-700 rounded-lg p-3 text-center">Tracking</Link>
            <Link to="/info-driver" className="block bg-gray-700 rounded-lg p-3 text-center">Info Driver</Link>
            <Link to="/checkpoints" className="block bg-gray-700 rounded-lg p-3 text-center">Checkpoints</Link>
            <Link to="/timbang-muat" className="block bg-blue-700 rounded-lg p-3 text-center">Timbang Muat</Link>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 p-8">
        <h1 className="text-2xl font-bold mb-6">Timbang Muat Truck</h1>

        <div className={`mb-4 text-white p-3 rounded ${rfidValue ? 'bg-green-500' : 'bg-red-500'}`}>
          {rfidValue ? `RFID Terdeteksi: ${rfidValue}` : 'Silakan scan kartu RFID...'}
        </div>

        {truck && (
          <div className="mb-6 bg-white shadow-lg rounded-lg p-4">
            <h2 className="text-lg font-semibold mb-2">Truck ID: {truck.truckId}</h2>
            <p><strong>Tipe:</strong> {truck.truckType}</p>
            <p><strong>Driver:</strong> {truck.driver}</p>
          </div>
        )}

        <form onSubmit={handleSubmit} className="bg-white p-6 rounded-lg shadow-lg space-y-4">
          <div>
            <label className="block mb-1 font-semibold">Jenis Barang</label>
            <input type="text" name="itemType" value={form.itemType} onChange={handleChange} required className="w-full border p-2 rounded" />
          </div>

          <div>
            <label className="block mb-1 font-semibold">Jumlah Barang (satuan/berat)</label>
            <input type="number" name="quantity" value={form.quantity} onChange={handleChange} required className="w-full border p-2 rounded" />
          </div>

          <div>
            <label className="block mb-1 font-semibold">Berat Bruto (kg)</label>
            <input type="number" name="bruto" value={form.bruto} onChange={handleChange} required className="w-full border p-2 rounded" />
          </div>

          <div>
            <label className="block mb-1 font-semibold">Berat Tara (kg)</label>
            <input type="number" name="tara" value={form.tara} onChange={handleChange} required className="w-full border p-2 rounded" />
          </div>

          <div>
            <label className="block mb-1 font-semibold">Netto (kg)</label>
            <input type="number" name="netto" value={form.netto} readOnly className="w-full border p-2 rounded bg-gray-100" />
          </div>

          <button type="submit" className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700">
            Simpan Data Timbang Muat
          </button>
        </form>
      </div>
    </div>
  );
};

export default TimbangMuat;
